**Gap:** `EchoModelProvider.Execute()` has no dedicated tests.

```go
// TestSkeleton: internal/model/provider/echo_test.go
package provider

import (
	"context"
	"testing"
)

func TestEchoModelProvider_Execute(t *testing.T) {
	e := NewEchoModelProvider()
	req := &ModelRequest{
		ContractID: "test-contract",
		Input:      map[string]any{"key": "value"},
	}

	resp, err := e.Execute(context.Background(), req)
	if err != nil {
		t.Fatalf("Execute should not error: %v", err)
	}
	if resp.Output["key"] != "value" {
		t.Errorf("Expected key=value echoed, got %v", resp.Output["key"])
	}
	if resp.Output["contract_id"] != "test-contract" {
		t.Errorf("Expected contract_id=test-contract, got %v", resp.Output["contract_id"])
	}
	if resp.Output["provider"] != "echo" {
		t.Errorf("Expected provider=echo, got %v", resp.Output["provider"])
	}
}

func TestEchoModelProvider_Execute_EmptyInput(t *testing.T) {
	e := NewEchoModelProvider()
	req := &ModelRequest{
		ContractID: "empty",
		Input:      map[string]any{},
	}

	resp, err := e.Execute(context.Background(), req)
	if err != nil {
		t.Fatalf("Execute should not error: %v", err)
	}
	if resp.Output["status"] != "ok" {
		t.Errorf("Expected status=ok, got %v", resp.Output["status"])
	}
}

func TestEchoModelProvider_ImplementsInterface(t *testing.T) {
	var _ ModelProvider = NewEchoModelProvider()
}
