func TestRegistry_ValidateScopes(t *testing.T) {
	r := NewRegistry()
	r.Register(&mockTool{name: "reader"}, []string{"filesystem:read"})
	r.Register(&mockTool{name: "writer"}, []string{"filesystem:write"})
	r.Register(&mockTool{name: "network-tool"}, []string{"network"})
	r.Register(&mockTool{name: "subprocess-tool"}, []string{"subprocess"})

	tests := []struct {
		toolName  string
		wantScope string
		hasScope  bool
	}{
		{"reader", "filesystem:read", true},
		{"writer", "filesystem:write", true},
		{"writer", "filesystem:read", false},
		{"network-tool", "network", true},
		{"subprocess-tool", "subprocess", true},
		{"nonexistent", "filesystem:read", false},
	}

	for _, tt := range tests {
		t.Run(tt.toolName+"_"+tt.wantScope, func(t *testing.T) {
			scopes := r.GetScopes(tt.toolName)
			found := false
			for _, s := range scopes {
				if s == tt.wantScope {
					found = true
					break
				}
			}
			if found != tt.hasScope {
				t.Errorf("GetScopes(%q) has %q = %v, want %v", tt.toolName, tt.wantScope, found, tt.hasScope)
			}
		})
	}
}
